"use client";
import type { SVGProps } from "react";
import { LimelightNav } from "@/components/ui/limelight-nav";
import { useState } from "react";

const HomeIcon = (p: SVGProps<SVGSVGElement>) => <svg {...p} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="m3 9 9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z" /></svg>;
const SearchIcon = (p: SVGProps<SVGSVGElement>) => <svg {...p} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="11" cy="11" r="8" /><path d="m21 21-4.3-4.3" /></svg>;
const BellIcon = (p: SVGProps<SVGSVGElement>) => <svg {...p} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M6 8a6 6 0 0 1 12 0c0 7 3 9 3 9H3s3-2 3-9" /><path d="M10.3 21a1.94 1.94 0 0 0 3.4 0" /></svg>;
const UserIcon = (p: SVGProps<SVGSVGElement>) => <svg {...p} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" /><circle cx="12" cy="7" r="4" /></svg>;

export default function BottomNav() {
  const [active, setActive] = useState(0);
  return (
    <div className="flex items-center justify-center p-16">
      <LimelightNav
        items={[
          { id: 1, icon: <HomeIcon className="w-6 h-6 text-white" />, label: "Home" },
          { id: 2, icon: <SearchIcon className="w-6 h-6 text-white" />, label: "Search" },
          { id: 3, icon: <BellIcon className="w-6 h-6 text-white" />, label: "Notifications" },
          { id: 4, icon: <UserIcon className="w-6 h-6 text-white" />, label: "Profile" },
        ]}
        defaultActiveIndex={active}
        onTabChange={setActive}
        limelightColor="#6366f1"
      />
    </div>
  );
}

